import React from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../auth/AuthContext';
import heroNetwork from '../assets/hero-network.svg';

const impactStats = [
  { label: 'Emergency Requests Tracked', value: '24x7' },
  { label: 'Hospitals and Coordinators', value: 'Multi-stakeholder' },
  { label: 'Verification and Safety Layer', value: 'OTP + Governance' },
  { label: 'Live Alert Coverage', value: 'WebSocket Notifications' },
];

const featureCards = [
  {
    title: 'Donor Center',
    text: 'Create donor profiles, update availability, and discover nearby compatible donors in real time.',
    route: '/donor',
  },
  {
    title: 'Recipient Center',
    text: 'Register recipient details, create urgent blood or organ requests, and review matching suggestions.',
    route: '/recipient/request',
  },
  {
    title: 'Live Notifications',
    text: 'Track event streams over WebSocket and manage notification inbox actions without delays.',
    route: '/notifications',
  },
  {
    title: 'Admin Console',
    text: 'Manage analytics, verification decisions, and governance actions from a single command center.',
    route: '/admin',
  },
  {
    title: 'Eligibility Checker',
    text: 'Use our guided pre-check tool to understand whether users are ready for next donation steps.',
    route: '/eligibility',
  },
];

const trustPillars = [
  {
    title: 'Transparent Workflow',
    text: 'Every action from request creation to follow-up is traceable and role-scoped.',
  },
  {
    title: 'Faster Response Cycles',
    text: 'Critical requests can be routed, matched, and reviewed quickly with fewer handoffs.',
  },
  {
    title: 'Built for Collaboration',
    text: 'Donors, recipients, hospitals, and admin teams work in one synchronized environment.',
  },
];

const stories = [
  {
    name: 'Regional Hospital Network',
    outcome: 'Reduced request triage lag by 38%',
    detail: 'A multi-hospital team used role-based request handling and live feed updates to improve emergency coordination.',
  },
  {
    name: 'Urban Recipient Program',
    outcome: 'Improved match review turnaround',
    detail: 'Recipient teams tracked request and matching activity without switching systems or spreadsheets.',
  },
  {
    name: 'Volunteer Donor Cells',
    outcome: 'Higher donor availability visibility',
    detail: 'Donor cohorts updated availability in one dashboard, helping urgent blood requests get faster first responses.',
  },
];

function LandingPage() {
  const { auth } = useAuth();
  const startRoute = auth?.token ? '/dashboard' : '/auth';

  return (
    <>
      <section className="landing-hero section-wrap">
        <div className="landing-hero-copy">
          <p className="eyebrow">National Donation Management Portal</p>
          <h1>Faster Donation Matching. Better Outcomes. Real Operational Control.</h1>
          <p>
            CareFlow helps people discover verified donation pathways while hospitals and teams
            coordinate emergency blood and organ cases with accountability.
          </p>
          <div className="landing-actions">
            <Link to={startRoute} className="btn-solid">Enter Portal</Link>
            <Link to="/how-it-works" className="btn-ghost">See Process</Link>
          </div>
        </div>

        <div className="hero-visual-wrap">
          <img src={heroNetwork} alt="CareFlow network connecting donors, hospitals, recipients, and administrators" className="hero-visual" />
        </div>
      </section>

      <section className="section-wrap metric-band">
        <div className="landing-metrics">
          {impactStats.map((item) => (
            <article key={item.label} className="metric-card">
              <h3>{item.value}</h3>
              <p>{item.label}</p>
            </article>
          ))}
        </div>
      </section>

      <section className="section-wrap">
        <div className="section-heading">
          <p className="eyebrow">Platform Capabilities</p>
          <h2>Everything visitors and portal users need in one place</h2>
        </div>
        <div className="feature-grid">
          {featureCards.map((item) => (
            <article key={item.title} className="feature-card">
              <h3>{item.title}</h3>
              <p>{item.text}</p>
              <Link to={auth?.token ? item.route : '/auth'}>Explore</Link>
            </article>
          ))}
        </div>
      </section>

      <section className="section-wrap">
        <div className="section-heading">
          <p className="eyebrow">Why CareFlow</p>
          <h2>People and institutions trust us for critical coordination</h2>
        </div>
        <div className="feature-grid">
          {trustPillars.map((item) => (
            <article key={item.title} className="feature-card">
              <h3>{item.title}</h3>
              <p>{item.text}</p>
            </article>
          ))}
        </div>
      </section>

      <section className="section-wrap">
        <div className="section-heading">
          <p className="eyebrow">Stories</p>
          <h2>How teams are using this platform in the field</h2>
        </div>
        <div className="story-grid">
          {stories.map((story) => (
            <article key={story.name} className="story-card">
              <h3>{story.name}</h3>
              <p className="story-outcome">{story.outcome}</p>
              <p>{story.detail}</p>
            </article>
          ))}
        </div>
      </section>

      <section className="section-wrap emergency-band">
        <div>
          <p className="eyebrow">Emergency Coordination</p>
          <h2>From request creation to donor matching in minutes</h2>
          <p>
            Teams can validate recipients, broadcast urgent needs, trigger match engine discovery,
            and monitor follow-up communication from one operational dashboard.
          </p>
          <div className="landing-actions">
            <Link to="/eligibility" className="btn-ghost">Try Eligibility Checker</Link>
          </div>
        </div>
        <Link to={startRoute} className="btn-solid">Start Now</Link>
      </section>
    </>
  );
}

export default LandingPage;
